// MARK: - Models

struct Stock: Codable, Identifiable {
    let id: String
    let symbol: String
    let name: String
    var currentPrice: Double
    var previousClose: Double
    var changePercent: Double
    var volume: Int
    var bid: Double
    var ask: Double
    var lastUpdated: Date
    
    var priceChange: Double {
        return currentPrice - previousClose
    }
    
    var isPositive: Bool {
        return priceChange >= 0
    }
}

struct Portfolio: Codable {
    var holdings: [Holding]
    var cashBalance: Double
    var totalValue: Double {
        return cashBalance + holdings.reduce(0) { $0 + $1.marketValue }
    }
    var totalGainLoss: Double {
        return holdings.reduce(0) { $0 + $1.gainLoss }
    }
    var totalGainLossPercent: Double {
        let totalCost = holdings.reduce(0) { $0 + $1.totalCost }
        guard totalCost > 0 else { return 0 }
        return (totalGainLoss / totalCost) * 100
    }
}

struct Holding: Codable, Identifiable {
    let id: String
    let symbol: String
    let name: String
    var quantity: Double
    var averageCost: Double
    var currentPrice: Double
    
    var totalCost: Double { quantity * averageCost }
    var marketValue: Double { quantity * currentPrice }
    var gainLoss: Double { marketValue - totalCost }
    var gainLossPercent: Double {
        guard totalCost > 0 else { return 0 }
        return (gainLoss / totalCost) * 100
    }
}

enum OrderType: String, Codable, CaseIterable {
    case market = "Market"
    case limit = "Limit"
    case stopLoss = "Stop Loss"
    case stopLimit = "Stop Limit"
}

enum OrderSide: String, Codable {
    case buy = "Buy"
    case sell = "Sell"
}

enum OrderStatus: String, Codable {
    case pending = "Pending"
    case filled = "Filled"
    case partiallyFilled = "Partially Filled"
    case cancelled = "Cancelled"
    case rejected = "Rejected"
    case expired = "Expired"
}

enum TimeInForce: String, Codable, CaseIterable {
    case day = "Day"
    case gtc = "GTC"
    case ioc = "IOC"
    case fok = "FOK"
}

struct TradeOrder: Codable, Identifiable {
    let id: String
    let symbol: String
    let side: OrderSide
    let type: OrderType
    var quantity: Double
    var limitPrice: Double?
    var stopPrice: Double?
    let timeInForce: TimeInForce
    var status: OrderStatus
    var filledQuantity: Double
    var filledPrice: Double?
    let createdAt: Date
    var updatedAt: Date
    
    var estimatedTotal: Double {
        let price = limitPrice ?? 0
        return quantity * price
    }
}

struct TradeConfirmation {
