// MARK: - Secure Keychain Manager

class SecureKeychainManager {
    static let shared = SecureKeychainManager()
    
    private let serviceName = "com.tradingapp.secure"
    
    func save(key: String, value: String) -> Bool {
        guard let data = value.data(using: .utf8) else { return false }
        
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: serviceName,
            kSecAttrAccount as String: key,
            kSecValueData as String: data,
            kSecAttrAccessible as String: kSecAttrAccessibleWhenUnlockedThisDeviceOnly
        ]
        
        SecItemDelete(query as CFDictionary)
        let status = SecItemAdd(query as CFDictionary, nil)
        return status == errSecSuccess
    }
    
    func retrieve(key: String) -> String? {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: serviceName,
            kSecAttrAccount as String: key,
            kSecReturnData as String: true,
            kSecMatchLimit as String: kSecMatchLimitOne
        ]
        
        var result: AnyObject?
        let status = SecItemCopyMatching(query as CFDictionary, &result)
        
        guard status == errSecSuccess, let data = result as? Data else { return nil }
        return String(data: data, encoding: .utf8)
    }
    
    func delete(key: String) -> Bool {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: serviceName,
            kSecAttrAccount as String: key
        ]
        return SecItemDelete(query as CFDictionary) == errSecSuccess
    }
}

// MARK: - SSL Pinning Session

class SecureURLSession: NSObject, URLSessionDelegate {
    static let shared = SecureURLSession()
    
    lazy var session: URLSession = {
        let config = URLSessionConfiguration.default
        config.tlsMinimumSupportedProtocolVersion = .TLSv12
        config.timeoutIntervalForRequest = 30
        config.timeoutIntervalForResource = 60
        config.httpAdditionalHeaders = [
            "Content-Type": "application/json",
            "Accept": "application/json"
        ]
        return URLSession(configuration: config, delegate: self, delegateQueue: nil)
    }()
    
    private var pinnedCertificates: [Data] = []
    
    override init() {
        super.init()
        loadPinnedCertificates()
    }
    
    private func loadPinnedCertificates() {
        if let certURL = Bundle.main.url(forResource: "trading_api", withExtension: "cer"),
           let certData = try? Data(contentsOf: certURL) {
            pinnedCertificates.append(certData)
        }
    }
    
    func urlSession(_ session: URLSession, didReceive challenge: URLAuthenticationChallenge,
                    completionHandler: @escaping (URLSession.AuthChallengeDisposition, URLCredential?) -> Void) {
        
        guard let serverTrust = challenge.protectionSpace.serverTrust,
              challenge.protectionSpace.authenticationMethod == NSURLAuthenticationMethodServerTrust else {
            completionHandler(.cancelAuthenticationChallenge, nil)
            return
        }
        
        if pinnedCertificates.isEmpty {
            completionHandler(.performDefaultHandling, nil)
            return
        }
        
        let certificateCount = SecTrustGetCertificateCount(serverTrust)
        var serverCertificates: [Data] = []
        
        for i in 0..<certificateCount {
            if let certificate = SecTrustCopyCertificateChain(serverTrust) {
                let certs = certificate as! [SecCertificate]
                if i < certs.count {
                    serverCertificates.append(SecCertificateCopyData(certs[i]) as Data)
                }
            }
        }
        
        let isPinned = pinnedCertificates.contains { pinnedCert in
            serverCertificates.contains(pinnedCert)
        }
        
        if isPinned {
            completionHandler(.useCredential, URLCredential(trust: serverTrust))
        } else {
            completionHandler(.performDefaultHandling, nil)
        }
    }
}

// MARK: - API Error

enum TradingAPIError: Error, LocalizedError {
    case unauthorized
    case insufficientFunds
    case insufficientShares
    case marketClosed
    case invalidOrder
    case networkError(Error)
    case serverError(Int, String)
    case decodingError(Error)
    case unknown
    case rateLimited
    case orderRejected(String)
    
    var errorDescription: String? {
        switch self {
        case .unauthorized: return "Session expired. Please log in again."
        case .insufficientFunds: return "Insufficient funds for this transaction."
        case .insufficientShares: return "Insufficient shares to sell."
        case .marketClosed: return "Market is currently closed."
        case .invalidOrder: return "Invalid order parameters."
        case .networkError(let error): return "Network error: \(error.localizedDescription)"
        case .serverError(let code, let message): return "Server error (\(code)): \(message)"
        case .decodingError: return "Failed to process server response."
        case .unknown: return "An unknown error occurred."
        case .rateLimited: return "Too many requests. Please try again later."
        case .orderRejected(let reason): return "Order rejected: \(reason)"
        }
    }
}

// MARK: - Trading API Service

class TradingAPIService {
    static let shared = TradingAPIService()
    
    private let baseURL = "https://api.tradingplatform.com/v1"
    private let session = SecureURLSession.shared.session
    private let keychain = SecureKeychainManager.shared
    
    private var authToken: String? {
        return keychain.retrieve(key: "auth_token")
    }
    
    private var refreshToken: String? {
        return keychain.retrieve(key: "refresh_token")
    }
    
    private let jsonDecoder: JSONDecoder = {
        let decoder = JSONDecoder()
        decoder.dateDecodingStrategy = .iso8601
        decoder.keyDecodingStrategy = .convertFromSnakeCase
        return decoder
    }()
    
    private let jsonEncoder: JSONEncoder = {
        let encoder = JSONEncoder()
        encoder.dateEncodingStrategy = .iso8601
        encoder.keyEncodingStrategy = .convertToSnakeCase
        return encoder
    }()
    
    // MARK: - Request Builder
    
    private func buildRequest(path: String, method: String, body: Data? = nil) throws -> URLRequest {
        guard let url = URL(string: "\(baseURL)\(path)") else {
            throw TradingAPIError.invalidOrder
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = method
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        request.setValue(UUID().uuidString, forHTTPHeaderField: "X-Request-ID")
        request.setValue(String(Date().timeIntervalSince1970), forHTTPHeaderField: "X-Timestamp")
        
        if let token = authToken {
            request.setValue("Bearer \(token)", forHTTPHeaderField: "Authorization")
        }
        
        if let body = body {
            request.httpBody = body
            let hmac = generateHMAC(data: body)
            request.setValue(hmac, forHTTPHeaderField: "X-Signature")
        }
        
        return request
    }
    
    private func generateHMAC(data: Data) -> String {
        guard let secret = keychain.retrieve(key: "api_secret"),
              let secretData = secret.data(using: .utf8) else {
            return ""
        }
        
        var hmac = [UInt8](repeating: 0, count: Int(CC_SHA256_DIGEST_LENGTH))
        data.withUnsafeBytes { dataBytes in
            secretData.withUnsafeBytes { keyBytes in
                CCHmac(CCHmacAlgorithm(kCCHmacAlgSHA256),
                        keyBytes.baseAddress, secretData.count,
                        dataBytes.baseAddress, data.count,
                        &hmac)
            }
        }
        return Data(hmac).base64EncodedString()
    }
    
    private func performRequest<T: Decodable>(_ request: URLRequest) async throws -> T {
        do {
            let (data, response) = try await session.data(for: request)
            
            guard let httpResponse = response as? HTTPURLResponse else {
                throw TradingAPIError.unknown
            }
            
            switch httpResponse.statusCode {
            case 200...299:
                do {
                    return try jsonDecoder.decode(T.self, from: data)
                } catch {
                    throw TradingAPIError.decodingError(error)
                }
            case 401:
                if try await refreshAuthToken() {
                    var retryRequest = request
                    if let newToken = authToken {
                        retryRequest.setValue("Bearer \(newToken)", forHTTPHeaderField: "Authorization")
                    }
                    let (retryData, retryResponse) = try await session.data(for: retryRequest)
                    guard let retryHttp = retryResponse as? HTTPURLResponse, retryHttp.statusCode == 200 else {
                        throw TradingAPIError.unauthorized
                    }
                    return try jsonDecoder.decode(T.self, from: retryData)
                }
                throw TradingAPIError.unauthorized
            case 403:
                throw TradingAPIError.insufficientFunds
            case 429:
                throw TradingAPIError.rateLimited
            default:
                let errorMessage = String(data: data, encoding: .utf8) ?? "Unknown error"
                throw TradingAPIError.serverError(httpResponse.statusCode, errorMessage)
            }
        } catch let error as TradingAPIError {
            throw error
        } catch {
            throw TradingAPIError.networkError(error)
        }
    }
    
    private func refreshAuthToken() async throws -> Bool {
        guard let refresh = refreshToken else { return false }
        
        let body = try jsonEncoder.encode(["refresh_token": refresh])
        let request = try buildRequest(path: "/auth/refresh", method: "POST", body: body)
        
        let (data, response) = try await session.data(for: request)
        guard let httpResponse = response as? HTTPURLResponse, httpResponse.statusCode == 200 else {
            return false
        }
        
        struct TokenResponse: Decodable {
            let accessToken: String
            let refreshToken: String
        }
        
        let tokenResponse = try jsonDecoder.decode(TokenResponse.self, from: data)
        _ = keychain.save(key: "auth_token", value: tokenResponse.accessToken)
        _ = keychain.save(key: "refresh_token", value: tokenResponse.refreshToken)
        return true
    }
    
    // MARK: - Authentication
    
    func login(email: String, password: String) async throws -> AccountInfo {
        struct LoginRequest: Encodable {
            let email: String
            let password: String
            let deviceId: String
        }
        
        struct LoginResponse: Decodable {
            let accessToken: String
            let refreshToken: String
            let account: AccountInfo
        }
        
        let deviceId = UIDevice.current.identifierForVendor?.uuidString ?? UUID().uuidString
        let loginRequest = LoginRequest(email: email, password: password, deviceId: deviceId)
        let body = try jsonEncoder.encode(loginRequest)
        let request = try buildRequest(path: "/auth/login", method: "POST", body: body)
        
        let response: LoginResponse = try await performRequest(request)
        _ = keychain.save(key: "auth_token", value: response.accessToken)
        _ = keychain.save(key: "refresh_token", value: response.refreshToken)
        return response.account
    }
    
    func logout() async throws {
        let request = try buildRequest(path: "/auth/logout", method: "POST")
        let _: EmptyResponse = try await performRequest(request)
        _ = keychain.delete(key: "auth_token")
        _ = keychain.delete(key: "refresh_token")
    }
    
    // MARK: - Market Data
    
    func getQuote(symbol: String) async throws -> Stock {
        let request = try buildRequest(path: "/market/quote/\(symbol)", method: "GET")
        return try await performRequest(request)
    }
    
    func getQuotes(symbols: [String]) async throws -> [Stock] {
        let symbolList = symbols.joined(separator: ",")
        let request = try buildRequest(path: "/market/quotes?symbols=\(symbolList)", method: "GET")
        return try await performRequest(request)
    }
    
    func searchStocks(query: String) async throws -> [Stock] {
        guard let encoded = query.addingPercentEncoding(withAllowedCharacters: .urlQueryAllowed) else {
            throw TradingAPIError.invalidOrder
        }
        let request = try buildRequest(path: "/market/search?q=\(encoded)", method: "GET")
        return try await performRequest(request)
    }
    
    // MARK: - Portfolio
    
    func getPortfolio() async throws -> Portfolio {
        let request = try buildRequest(path: "/portfolio", method: "GET")
        return try await performRequest(request)
    }
    
    func getAccountInfo() async throws -> AccountInfo {
        let request = try buildRequest(path: "/account", method: "GET")
        return try await performRequest(request)
    }
    
    // MARK: - Orders
    
    func placeOrder(order: TradeOrder) async throws -> TradeOrder {
        struct OrderRequest: Encodable {
            let symbol: String
            let side: String
            let type: String
            let quantity: Double
            let limitPrice: Double?
            let stopPrice: Double?
            let timeInForce: String
        }
        
        let orderRequest = OrderRequest(
            symbol: order.symbol,
            side: order.side.rawValue.lowercased(),
            type: order.type.rawValue.lowercased(),
            quantity: order.quantity,
            limitPrice: order.limitPrice,
            stopPrice: order.stopPrice,
            timeInForce: order.timeInForce.rawValue.lowercased()
        )
        
        let body = try jsonEncoder.encode(orderRequest)
        let request = try buildRequest(path: "/orders", method: "POST", body: body)
        return try await performRequest(request)
    }
    
    func cancelOrder(orderId: String) async throws -> TradeOrder {
        let request = try buildRequest(path: "/orders/\(orderId)/cancel", method: "POST")
        return try await performRequest(request)
    }
    
    func getOrders(status: OrderStatus? = nil) async throws -> [TradeOrder] {
        var path = "/orders"
        if let status = status {
            path += "?status=\(status.rawValue.lowercased())"
        }
        let request = try buildRequest(path: path, method: "GET")
        return try await performRequest(request)
    }
    
    func getOrder(orderId: String) async throws -> TradeOrder {
        let request = try buildRequest(path: "/orders/\(orderId)", method: "GET")
        return try await performRequest(request)
    }
}

