// MARK: - WebSocket for Real-Time Data

class RealTimeDataService: NSObject, URLSessionWebSocketDelegate {
    static let shared = RealTimeDataService()
    
    private var webSocket: URLSessionWebSocketTask?
    private var subscribedSymbols: Set<String> = []
    private var isConnected = false
    private var reconnectAttempts = 0
    private let maxReconnectAttempts = 5
    private var reconnectTimer: Timer?
    
    let priceUpdatePublisher = PassthroughSubject<MarketData, Never>()
    let connectionStatusPublisher = PassthroughSubject<Bool, Never>()
    let orderUpdatePublisher = PassthroughSubject<TradeOrder, Never>()
    
    func connect() {
        guard !isConnected else { return }
        
        let urlString = "wss://ws.tradingplatform.com/v1/stream"
        guard let url = URL(string: urlString) else { return }
        
        var request = URLRequest(url: url)
        if let token = SecureKeychainManager.shared.retrieve(key: "auth_token") {
            request.setValue("Bearer \(token)", forHTTPHeaderField: "Authorization")
        }
        
        let session = URLSession(configuration: .default, delegate: self, delegateQueue: OperationQueue())
        webSocket = session.webSocketTask(with: request)
        webSocket?.resume()
        
        isConnected = true
        reconnectAttempts = 0
        connectionStatusPublisher.send(true)
        
        receiveMessage()
        startPingTimer()
    }
    
    func disconnect() {
        webSocket?.cancel(with: .normalClosure, reason: nil)
        webSocket = nil
        isConnected = false
        reconnectTimer?.invalidate()
        connectionStatusPublisher.send(false)
    }
    
    func subscribe(symbols: [String]) {
        subscribedSymbols.formUnion(symbols)
        
        let message: [String: Any] = [
            "action": "subscribe",
            "symbols": symbols,
            "channels": ["quotes", "trades"]
        ]
        
        sendJSON(message)
    }
    
    func unsubscribe(symbols: [String]) {
        subscribedSymbols.subtract(symbols)
        
        let message: [String: Any] = [
            "action": "unsubscribe",
            "symbols": symbols
        ]
        
        sendJSON(message)
    }
    
    private func sendJSON(_ dict: [String: Any]) {
        guard let data = try? JSONSerialization.data(withJSONObject: dict),
              let string = String(data: data, encoding: .utf8) else { return }
        
        webSocket?.send(.string(string)) { error in
            if let error = error {
                print("WebSocket send error: \(error)")
            }
        }
    }
    
    private func receiveMessage() {
        webSocket?.receive { [weak self] result in
            switch result {
            case .success(let message):
                switch message {
                case .string(let text):
                    self?.handleMessage(text)
                case .data(let data):
                    if let text = String(data: data, encoding: .utf8) {
                        self?.handleMessage(text)
                    }
                @unknown default:
                    break
                }
                self?.receiveMessage()
                
            case .failure(let error):
                print("WebSocket receive error: \(error)")
                self?.handleDisconnection()
            }
        }
    }
    
    private func handleMessage(_ text: String) {
        guard let data = text.data(using: .utf8),
              let json = try? JSONSerialization.jsonObject(with: data) as? [String: Any],
              let type = json["type"] as? String else { return }
        
        switch type {
        case "quote":
            if let marketData = try? JSONDecoder().decode(MarketData.self, from: data) {
                DispatchQueue.main.async {
                    self.priceUpdatePublisher.send(marketData)
                }
            }
        case "order_update":
            if let order = try? JSONDecoder().decode(TradeOrder.self, from: data) {
                DispatchQueue.main.async {
                    self.orderUpdatePublisher.send(order)
                }
            }
        default:
            break
        }
    }
    
    private func handleDisconnection() {
        isConnected = false
        connectionStatusPublisher.send(false)
        
        guard reconnectAttempts < maxReconnectAttempts else { return }
        
        let delay = pow(2.0, Double(reconnectAttempts))
        reconnectAttempts += 1
        
        DispatchQueue.main.asyncAfter(deadline: .now() + delay) { [weak self] in
            self?.connect()
            if let symbols = self?.subscribedSymbols, !symbols.isEmpty {
                self?.subscribe(symbols: Array(symbols))
            }
        }
    }
    
    private func startPingTimer() {
        reconnectTimer?.invalidate()
        reconnectTimer = Timer.scheduledTimer(withTimeInterval: 30, repeats: true) { [weak self] _ in
            self?.webSocket?.sendPing { error in
                if let error = error {
                    print("Ping error: \(error)")
                    self?.handleDisconnection()
                }
            }
        }
    }
    
    func urlSession(_ session: URLSession, webSocketTask: URLSessionWebSocketTask,
                    didOpenWithProtocol protocol: String?) {
        isConnected = true
        connectionStatusPublisher.send(true)
    }
    
    func urlSession(_ session: URLSession, webSocketTask: URLSessionWebSocketTask,
                    didCloseWith closeCode: URLSessionWebSocketTask.CloseCode, reason: Data?) {
        handleDisconnection()
    }
}

// MARK: - Trading Engine

class TradingEngine: ObservableObject {
    static let shared = TradingEngine()
    
    @Published var portfolio: Portfolio?
    @Published var accountInfo: AccountInfo?
    @Published var openOrders: [TradeOrder] = []
    @Published var orderHistory: [TradeOrder] = []
    @Published var watchlistStocks: [Stock] = []
    @Published var isLoading = false
    @Published var error: TradingAPIError?
    @Published var isConnected = false
    
    private let api = TradingAPIService.shared
    private let realTimeService = RealTimeDataService.shared
    private var cancellables = Set<AnyCancellable>()
    
    init() {
        setupSubscriptions()
    }
    
    private func setupSubscriptions() {
        realTimeService.priceUpdatePublisher
            .receive(on: DispatchQueue.main)
            .sink { [weak self] marketData in
                self?.handlePriceUpdate(marketData)
            }
            .store(in: &cancellables)
        
        realTimeService.orderUpdatePublisher
            .receive(on: DispatchQueue.main)
            .sink { [weak self] order in
                self?.handleOrderUpdate(order)
            }
            .store(in: &cancellables)
        
        realTimeService.connectionStatusPublisher
            .receive(on: DispatchQueue.main)
            .sink { [weak self] connected in
                self?.isConnected = connected
            }
            .store(in: &cancellables)
    }
    
    private func handlePriceUpdate(_ data: MarketData) {
        // Update watchlist
        if let index = watchlistStocks.firstIndex(where: { $0.symbol == data.symbol }) {
            watchlistStocks[index].currentPrice = data.price
            watchlistStocks[index].bid = data.bid
            watchlistStocks[index].ask = data.ask
            watchlistStocks[index].volume = data.volume
            watchlistStocks[index].lastUpdated = data.timestamp
            
            let change = data.price - watchlistStocks[index].previousClose
            let changePercent = (change / watchlistStocks[index].previousClose) * 100
            watchlistStocks[index].changePercent = changePercent
        }
        
        // Update portfolio holdings
        if var portfolio = portfolio,
           let index = portfolio.holdings.firstIndex(where: { $0.symbol == data.symbol }) {
            portfolio.holdings[index].currentPrice = data.price
            self.portfolio = portfolio
        }
    }
    
    private func handleOrderUpdate(_ order: TradeOrder) {
        if let index = openOrders.firstIndex(where: { $0.id == order.id }) {
            if order.status == .filled || order.status == .cancelled || order.status == .rejected {
                openOrders.remove(at: index)
                orderHistory.insert(order, at: 0)
            } else {
                openOrders[index] = order
            }
        }
        
        if order.status == .filled {
            Task { await refreshPortfolio() }
        }
    }
    
    // MARK: - Public Methods
    
    func connectRealTime() {
        realTimeService.connect()
    }
    
    func disconnectRealTime() {
        realTimeService.disconnect()
    }
    
    func subscribeToSymbols(_ symbols: [String]) {
        realTimeService.subscribe(symbols: symbols)
    }
    
    @MainActor
    func refreshPortfolio() async {
        isLoading = true
        error = nil
        
        do {
            async let portfolioTask = api.getPortfolio()
            async let accountTask = api.getAccountInfo()
            async let ordersTask = api.getOrders(status: .pending)
            
            let (fetchedPortfolio, fetchedAccount, fetchedOrders) = try await (portfolioTask, accountTask, ordersTask)
            
            portfolio = fetchedPortfolio
            accountInfo = fetchedAccount
            openOrders = fetchedOrders
            
            let symbols = fetchedPortfolio.holdings.map { $0.symbol }
            subscribeToSymbols(symbols)
        } catch let apiError as TradingAPIError {
            self.error = apiError
        } catch {
            self.error = .networkError(error)
        }
        
        isLoading = false
    }
    
    @MainActor
    func loadOrderHistory() async {
        do {
            orderHistory = try await api.getOrders()
        } catch let apiError as TradingAPIError {
            self.error = apiError
        } catch {
            self.error = .networkError(error)
        }
    }
    
    @MainActor
    func loadWatchlist(_ symbols: [String]) async {
        do {
            watchlistStocks = try await api.getQuotes(symbols: symbols)
            subscribeToSymbols(symbols)
        } catch let apiError as TradingAPIError {
            self.error = apiError
        } catch {
            self.error = .networkError(error)
        }
    }
    
    @MainActor
    func searchStocks(query: String) async -> [Stock] {
        do {
            return try await api.searchStocks(query: query)
        } catch {
            return []
        }
    }
    
    func validateOrder(side: OrderSide, symbol: String, quantity: Double,
                       orderType: OrderType, limitPrice: Double?,
                       currentPrice: Double) -> TradingAPIError? {
        guard quantity > 0 else {
            return .invalidOrder
        }
        
        if side == .buy {
            let estimatedCost = (limitPrice ?? currentPrice) * quantity
            if let account = accountInfo, estimatedCost > account.buyingPower {
                return .insufficientFunds
            }
        }
        
        if side == .sell {
            if let holding = portfolio?.holdings.first(where: { $0.symbol == symbol }),
               quantity > holding.quantity {
                return .insufficientShares
            } else if portfolio?.holdings.first(where: { $0.symbol == symbol }) == nil {
                return .insufficientShares
            }
        }
        
        if orderType == .limit || orderType == .stopLimit {
            guard let price = limitPrice, price > 0 else {
                return .invalidOrder
            }
        }
        
        return nil
    }
    
    func createTradeConfirmation(side: OrderSide, symbol: String, quantity: Double,
                                 orderType: OrderType, limitPrice: Double?,
                                 stopPrice: Double?, timeInForce: TimeInForce,
                                 currentPrice: Double) -> TradeConfirmation {
        let order = TradeOrder(
            id: UUID().uuidString,
            symbol: symbol,
            side: side,
            type: orderType,
            quantity: quantity,
            limitPrice: orderType == .market ? nil : limitPrice,
            stopPrice: stopPrice,
            timeInForce: timeInForce,
            status: .pending,
            filledQuantity: 0,
            filledPrice: nil,
            createdAt: Date(),
            updatedAt: Date()
        )
        
        let price = limitPrice ?? currentPrice
        let estimatedCost = price * quantity
        let commission = max(0.0, estimatedCost * 0.0) // Commission-free
        let totalCost = estimatedCost + commission
        
        return TradeConfirmation(
            order: order,
            estimatedCost: estimatedCost,
            commission: commission,
            totalCost: totalCost
        )
    }
    
    @MainActor
    func executeOrder(_ order: TradeOrder) async throws -> TradeOrder {
        isLoading = true
        defer { isLoading = false }
        
        do {
            let executedOrder = try await api.placeOrder(order: order)
            
            if executedOrder.status == .pending || executedOrder.status == .partiallyFilled {
                openOrders.append(executedOrder)
            } else {
                orderHistory.insert(executedOrder, at: 0)
            }
            
            await refreshPortfolio()
            return executedOrder
        } catch let apiError as TradingAPIError {
            self.error = apiError
            throw apiError
        } catch {
            let tradingError = TradingAPIError.networkError(error)
            self.error = tradingError
            throw tradingError
        }
    }
    
    @MainActor
    func cancelOrder(_ orderId: String) async throws {
        do {
            let cancelledOrder = try await api.cancelOrder(orderId: orderId)
            if let index = openOrders.firstIndex(where: { $0.id == orderId }) {
                openOrders.remove(at: index)
            }
            orderHistory.insert(cancelledOrder, at: 0)
        } catch let apiError as TradingAPIError {
            self.error = apiError
            throw apiError
        }
    }
}

// MARK: - View Models

class TradeViewModel: ObservableObject {
    @Published var stock: Stock?
    @Published var orderSide: OrderSide = .buy
    @Published var orderType: OrderType = .market
    @Published var quantity: String = ""
    @Published var limitPrice: String = ""
    @Published var stopPrice: String = ""
    @Published var timeInForce: TimeInForce = .day
    @Published var validationError: String?
    @Published var isExecuting = false
    @Published var showConfirmation = false
    @Published var tradeConfirmation: TradeConfirmation?
    @Published var executedOrder: TradeOrder?
    @Published var showSuccess = false
    
    private let engine = TradingEngine.shared
    private var cancellables = Set<AnyCancellable>()
    
    var quantityDouble: Double {
        return Double(quantity) ?? 0
    }
    
    var limitPriceDouble: Double? {
        return Double(limitPrice)
    }
    
    var stopPriceDouble: Double? {
        return Double(stopPrice)
    }
    
    var estimatedTotal: Double {
        guard let stock = stock else { return 0 }
        let price = limitPriceDouble ?? stock.currentPrice
        return price * quantityDouble
    }
    
    var maxBuyQuantity: Int {
        guard let stock = stock, let account = engine.accountInfo else { return 0 }
        return Int(account.buyingPower / stock.ask)
    }
    
    var maxSellQuantity: Double {
        guard let stock = stock,
              let holding = engine.portfolio?.holdings.first(where: { $0.symbol == stock.symbol }) else {
            return 0
        }
        return holding.quantity
    }
    
    func loadStock(symbol: String) async {
        do {
            let fetchedStock = try await TradingAPIService.shared.getQuote(symbol: symbol)
            await MainActor.run {
                self.stock = fetchedStock
                if self.orderType == .limit {
                    self.limitPrice = String(format: "%.2f", fetchedStock.currentPrice)
                }
            }
        } catch {
            await MainActor.run {
                self.validationError = error.localizedDescription
            }
        }
    }
    
    func validate() -> Bool {
        guard let stock = stock else {
            validationError = "Stock data not available"
            return false
        }
        
        if let error = engine.validateOrder(
            side: orderSide,
            symbol: stock.symbol,
            quantity: quantityDouble,
            orderType: orderType,
            limitPrice: limitPriceDouble,
            currentPrice: stock.currentPrice
        ) {
            validationError = error.errorDescription
            return false
        }
        
        validationError = nil
        return true
    }
    
    func prepareConfirmation() {
        guard validate(), let stock = stock else { return }
        
        tradeConfirmation = engine.createTradeConfirmation(
            side: orderSide,
            symbol: stock.symbol,
            quantity: quantityDouble,
            orderType: orderType,
            limitPrice: limitPriceDouble,
            stopPrice: stopPriceDouble,
            timeInForce: timeInForce,
            currentPrice: stock.currentPrice
        )
        showConfirmation = true
    }
    
    func executeOrder() async {
        guard let confirmation = tradeConfirmation else { return }
        
        await MainActor.run { isExecuting = true }
        
        do {
            let order = try await engine.executeOrder(confirmation.order)
            await MainActor.run {
                executedOrder = order
                isExecuting = false
                showConfirmation = false
                showSuccess = true
            }
        } catch {
            await MainActor.run {
                validationError = error.localizedDescription
                isExecuting = false
            }
        }
    }
}

class PortfolioViewModel: ObservableObject {
    @Published var portfolio: Portfolio?
    @Published var accountInfo: AccountInfo?
    @Published var isLoading = false
    @Published var error: String?
    
    private let engine = TradingEngine.shared
    private var cancellables = Set<AnyCancellable>()
    
    init() {
        engine.$portfolio
            .receive(on: DispatchQueue.main)
            .assign(to: &$portfolio)
        
        engine.$accountInfo
            .receive(on: DispatchQueue.main)
            .assign(to: &$accountInfo)
        
        engine.$isLoading
            .receive(on: DispatchQueue.main)
            .assign(to: &$isLoading)
        
        engine.$error
            .receive(on: DispatchQueue.main)
            .map { $0?.errorDescription }
            .assign(to: &$error)
    }
    
    func refresh() async {
        await engine.refreshPortfolio()
    }
}

// MARK: - UI Components

class PriceFormatter {
    static func format(_ price: Double) -> String {
        return String(format: "$%.2f", price)
    }
    
    static func formatChange(_ change: Double) -> String {
        let sign = change >= 0 ? "+" : ""
        return "\(sign)\(String(format: "%.2f", change))"
    }
    
    static func formatPercent(_ percent: Double) -> String {
        let sign = percent >= 0 ? "+" : ""
        return "\(sign)\(String(format: "%.2f", percent))%"
    }
    
    static func formatQuantity(_ quantity: Double) -> String {
        if quantity == Double(Int(quantity)) {
            return String(Int(quantity))
        }
        return String(format: "%.4f", quantity)
    }
    
    static func formatVolume(_ volume: Int) -> String {
        if volume >= 1_000_000 {
            return String(format: "%.1fM", Double(volume) / 1_000_000)
        } else if volume >= 1_000 {
            return String(format: "%.1fK", Double(volume) / 1_000)
        }
        return "\(volume)"
    }
}

