            await viewModel.refresh()
        }
    }
    
    private func setupUI() {
        view.addSubview(scrollView)
        scrollView.addSubview(contentStack)
        
        let headerStack = UIStackView(arrangedSubviews: [totalValueLabel, gainLossLabel, cashBalanceLabel, buyingPowerLabel])
        headerStack.axis = .vertical
        headerStack.spacing = 4
        
        let headerCard = createCard(content: headerStack)
        contentStack.addArrangedSubview(headerCard)
        contentStack.addArrangedSubview(holdingsHeaderLabel)
        contentStack.addArrangedSubview(holdingsStack)
        contentStack.addArrangedSubview(emptyLabel)
        
        NSLayoutConstraint.activate([
            scrollView.topAnchor.constraint(equalTo: view.safeAreaLayoutGuide.topAnchor),
            scrollView.leadingAnchor.constraint(equalTo: view.leadingAnchor),
            scrollView.trailingAnchor.constraint(equalTo: view.trailingAnchor),
            scrollView.bottomAnchor.constraint(equalTo: view.bottomAnchor),
            
            contentStack.topAnchor.constraint(equalTo: scrollView.topAnchor),
            contentStack.leadingAnchor.constraint(equalTo: scrollView.leadingAnchor),
            contentStack.trailingAnchor.constraint(equalTo: scrollView.trailingAnchor),
            contentStack.bottomAnchor.constraint(equalTo: scrollView.bottomAnchor),
            contentStack.widthAnchor.constraint(equalTo: scrollView.widthAnchor)
        ])
    }
    
    private func createCard(content: UIView) -> UIView {
        let card = UIView()
        card.backgroundColor = .secondarySystemBackground
        card.layer.cornerRadius = 12
        card.translatesAutoresizingMaskIntoConstraints = false
        
        content.translatesAutoresizingMaskIntoConstraints = false
        card.addSubview(content)
        
        NSLayoutConstraint.activate([
            content.topAnchor.constraint(equalTo: card.topAnchor, constant: 16),
            content.leadingAnchor.constraint(equalTo: card.leadingAnchor, constant: 16),
            content.trailingAnchor.constraint(equalTo: card.trailingAnchor, constant: -16),
            content.bottomAnchor.constraint(equalTo: card.bottomAnchor, constant: -16)
        ])
        
        return card
    }
    
    private func bindViewModel() {
        viewModel.$portfolio
            .receive(on: DispatchQueue.main)
            .sink { [weak self] portfolio in
                self?.updatePortfolioUI(portfolio)
            }
            .store(in: &cancellables)
        
        viewModel.$accountInfo
            .receive(on: DispatchQueue.main)
            .sink { [weak self] info in
                self?.updateAccountUI(info)
            }
            .store(in: &cancellables)
        
        viewModel.$isLoading
            .receive(on: DispatchQueue.main)
            .sink { [weak self] loading in
                if !loading {
                    self?.scrollView.refreshControl?.endRefreshing()
                }
            }
            .store(in: &cancellables)
    }
    
    private func updatePortfolioUI(_ portfolio: Portfolio?) {
        guard let portfolio = portfolio else { return }
        
        totalValueLabel.text = PriceFormatter.format(portfolio.totalValue)
        
        let gainLoss = portfolio.totalGainLoss
        let gainLossPercent = portfolio.totalGainLossPercent
        gainLossLabel.text = "\(PriceFormatter.formatChange(gainLoss)) (\(PriceFormatter.formatPercent(gainLossPercent)))"
        gainLossLabel.textColor = gainLoss >= 0 ? .systemGreen : .systemRed
        
        cashBalanceLabel.text = "Cash: \(PriceFormatter.format(portfolio.cashBalance))"
        
        emptyLabel.isHidden = !portfolio.holdings.isEmpty
        holdingsStack.isHidden = portfolio.holdings.isEmpty
        
        holdingsStack.arrangedSubviews.forEach { $0.removeFromSuperview() }
        
        for holding in portfolio.holdings {
            let holdingView = createHoldingView(holding)
            holdingsStack.addArrangedSubview(holdingView)
        }
    }
    
    private func updateAccountUI(_ info: AccountInfo?) {
        guard let info = info else { return }
        buyingPowerLabel.text = "Buying Power: \(PriceFormatter.format(info.buyingPower))"
    }
    
    private func createHoldingView(_ holding: Holding) -> UIView {
        let card = UIView()
        card.backgroundColor = .secondarySystemBackground
        card.layer.cornerRadius = 10
        
        let symbolLabel = UILabel()
        symbolLabel.text = holding.symbol
        symbolLabel.font = .systemFont(ofSize: 17, weight: .bold)
        
        let nameLabel = UILabel()
        nameLabel.text = holding.name
        nameLabel.font = .systemFont(ofSize: 13, weight: .regular)
        nameLabel.textColor = .secondaryLabel
        
        let quantityLabel = UILabel()
        quantityLabel.text = "\(PriceFormatter.formatQuantity(holding.quantity)) shares"
        quantityLabel.font = .systemFont(ofSize: 13, weight: .regular)
        quantityLabel.textColor = .secondaryLabel
        
        let leftStack = UIStackView(arrangedSubviews: [symbolLabel, nameLabel, quantityLabel])
        leftStack.axis = .vertical
        leftStack.spacing = 2
        
        let valueLabel = UILabel()
        valueLabel.text = PriceFormatter.format(holding.marketValue)
        valueLabel.font = .systemFont(ofSize: 17, weight: .semibold)
        valueLabel.textAlignment = .right
        
        let glLabel = UILabel()
        glLabel.text = "\(PriceFormatter.formatChange(holding.gainLoss)) (\(PriceFormatter.formatPercent(holding.gainLossPercent)))"
        glLabel.font = .systemFont(ofSize: 13, weight: .medium)
        glLabel.textColor = holding.gainLoss >= 0 ? .systemGreen : .systemRed
        glLabel.textAlignment = .right
        
        let priceLabel = UILabel()
        priceLabel.text = "@ \(PriceFormatter.format(holding.currentPrice))"
        priceLabel.font = .systemFont(ofSize: 13, weight: .regular)
        priceLabel.textColor = .secondaryLabel
        priceLabel.textAlignment = .right
        
        let rightStack = UIStackView(arrangedSubviews: [valueLabel, glLabel, priceLabel])
        rightStack.axis = .vertical
        rightStack.spacing = 2
        rightStack.alignment = .trailing
        
        let hStack = UIStackView(arrangedSubviews: [leftStack, rightStack])
        hStack.axis = .horizontal
        hStack.distribution = .equalSpacing
        hStack.translatesAutoresizingMaskIntoConstraints = false
        
        card.addSubview(hStack)
        
        NSLayoutConstraint.activate([
            hStack.topAnchor.constraint(equalTo: card.topAnchor, constant: 12),
            hStack.leadingAnchor.constraint(equalTo: card.leadingAnchor, constant: 16),
            hStack.trailingAnchor.constraint(equalTo: card.trailingAnchor, constant: -16),
            hStack.bottomAnchor.constraint(equalTo: card.bottomAnchor, constant: -12)
        ])
        
        let tapGesture = UITapGestureRecognizer(target: self, action: #selector(holdingTapped(_:)))
        card.addGestureRecognizer(tapGesture)
        card.tag = holding.symbol.hashValue
        card.accessibilityIdentifier = holding.symbol
        
        return card
    }
    
    @objc private func holdingTapped(_ gesture: UITapGestureRecognizer) {
        guard let view = gesture.view,
              let symbol = view.accessibilityIdentifier else { return }
        
        let tradeVC = TradeViewController(symbol: symbol)
        navigationController?.pushViewController(tradeVC, animated: true)
    }
    
    @objc private func handleRefresh() {
        Task {
            await viewModel.refresh()
        }
    }
}

